mapper.insert:
/* com.matjzing.mapper.FrontCategoryMapper.insertFrontCategory */
INSERT INTO CATEGORY (
	  MEMBER_SEQ /**/
	, NAME /**/
	, EMOJI /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  COALESCE(NULLIF(#{memberSeq}, 0), #{registerSeq})
	, #{name}
	, #{emoji}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)

mapper.update:
		/* com.matjzing.mapper.FrontCategoryMapper.updateFrontCategory */
    	UPDATE CATEGORY SET
			  UPDATER_SEQ = #{updaterSeq}
			, UPDATER_IP = #{updaterIp}
			, UPDATE_DT = NOW(3)
			, NAME = #{name}
			, EMOJI = #{emoji}
		WHERE
			CATEGORY_SEQ = #{categorySeq}
			AND MEMBER_SEQ = COALESCE(NULLIF(#{memberSeq}, 0), #{registerSeq})
			AND MEMBER_SEQ != 0
			AND USE_YN = TRUE

		/* com.matjzing.mapper.FrontCategoryMapper.deleteFrontCategory */
    	UPDATE CATEGORY SET
			  UPDATER_SEQ = #{updaterSeq}
			, UPDATER_IP = #{updaterIp}
			, UPDATE_DT = NOW(3)
			, USE_YN = FALSE
		WHERE
			CATEGORY_SEQ = #{categorySeq}
			AND MEMBER_SEQ = COALESCE(NULLIF(#{memberSeq}, 0), #{registerSeq})
			AND MEMBER_SEQ != 0
			AND USE_YN = TRUE
